/// trap_handler函数的内部处理函数
#[no_mangle]
pub extern "C" fn trap_handler_inner() -> ! {
    unsafe {
        // 屏蔽发生在S态下的异常
        stvec::write(trap_handler_in_kernel as usize, TrapMode::Direct);
    }
    let mut context = PROCESS_MANAGER.write().get_mut_current_context();
    let scause = scause::read();
    let stval = stval::read();
    match scause.cause() {
        Trap::Interrupt(Interrupt::SupervisorTimer) => timer_interrupt_hanlder(),
        Trap::Exception(Exception::UserEnvCall) => {
            context.sepc += 4; // 将sepc修改为ecall指令后的下一条指令地址
            // println!("syscall {}", context.x[17]);
            let res = syscall::syscall(
                context.x[17],
                [
                    context.x[10],
                    context.x[11],
                    context.x[12],
                    context.x[13],
                    context.x[14],
                    context.x[15],
                ],
            ) as usize;
            // cx is changed during sys_exec, so we have to call it again
            context = PROCESS_MANAGER.write().get_mut_current_context();
            context.x[10] = res;
        }
        Trap::Exception(Exception::IllegalInstruction) => {
            panic!("[KERNEL] IllegalInstruction");
        }
        _ => {
            panic!(
                "Unsupported trap {:?}, stval = {:#x}!",
                scause.cause(),
                stval
            );
        }
    }

    jump_restore()
}

#[no_mangle]
pub fn jump_restore() -> ! {
    unsafe {
        // 恢复异常处理函数的地址为跳板位置
        stvec::write(TRAMPOLINE_VIRT_ADDR as usize, TrapMode::Direct);
    }
    /// 之前的锁无法直接释放，因为进入了汇编代码
    unsafe {
        while PROCESS_MANAGER.reader_count() != 0 {
            PROCESS_MANAGER.force_read_decrement();
        }
        PROCESS_MANAGER.force_write_unlock();
    }
    extern "C" {
        fn _trap_handler();
        fn _restore(user_satp: usize, context_ptr: *mut Context);
    }

    let user_satp = PROCESS_MANAGER.read().get_current_pcb().vms.get_satp();
    // println!("jump restore {}, satp {:x?} {:x?}",PROCESS_MANAGER.read().get_current_pcb().pid, user_satp, PROCESS_MANAGER.read().get_current_pcb().vms.vms.get_pa(VirtAddr::new(CONTEXT_VIRT_ADDR)).unwrap().0.get_value());
    // 计算_restore的虚拟地址
    let restore_va = _restore as usize - _trap_handler as usize + TRAMPOLINE_VIRT_ADDR;
    unsafe {
        asm!(
            "fence.i", // 清空指令缓存
            "jr {}",
            in(reg) restore_va,
            in("a0") user_satp,
            in("a1") CONTEXT_VIRT_ADDR,
            options(noreturn)
        );
    }
}

