/// 获取自1970年1月1日0时0分0秒到现在的时间和时区
///
/// 时区结构的使用已经过时，tz参数通常应该被指定为NULL
///
/// 成功返回0，错误返回-1，如地址错误
pub fn sys_gettimeofday(tv: *mut TimeVal, _tz: *mut TimeZone) -> i32 {
    let usec = get_microsecond();
    let sec = usec / 1000_000;
    let time_val = TimeVal {
        tv_sec: sec,
        tv_usec: usec,
    };
    PROCESS_MANAGER.write().get_mut_current_pcb().vms.write(VirtAddr::new(tv as usize), &time_val);
    0
}

